        if f"[{i}]" not in cited:
            continue
        authors = entry.get("authors") or []
        who = (authors[0] if authors else "").strip()
        if len(authors) > 1:
            who += " et al."
        baskets = entry.get("baskets") or []
        subj = pred = ""
        for b in baskets:
            subj = (b.get("subject") or "").strip()
            pred = (b.get("predicate") or "").strip()
            if subj:
                break
        if not (who and subj):
            continue
        rows.append((who, subj, pred or "—"))
        if len(rows) >= limit:
            break
    if len(rows) < 3:
        return ""
    out = ["", "**Table 1: Key studies synthesised in this review**", "",
           "| Study | Focus | Reported relation |", "|---|---|---|"]
    for who, subj, pred in rows:
        out.append(f"| {who} | {subj} | {pred} |")
    out.append("")
    return "\n".join(out)

